820:pub fn validate_structured_collaboration_record(
821:    family: StructuredCollaborationRecordFamily,
822:    value: &Value,
823:) -> StructuredCollaborationValidationResult {
824:    let descriptor = structured_collaboration_schema_descriptor(family);
825:    let mut result = StructuredCollaborationValidationResult::success(family);
826:
827:    let Some(obj) = value.as_object() else {
828:        result.push_issue(
829:            StructuredCollaborationValidationCode::InvalidFieldType,
830:            "$",
831:            Some("object".to_string()),
832:            Some(json_type_name(value).to_string()),
833:            "structured collaboration record must be a JSON object",
834:        );
835:        return result;
836:    };
837:
838:    validate_expected_string(
839:        obj.get("schema_id"),
840:        "schema_id",
841:        descriptor.schema_id,
842:        &mut result,
843:    );
844:    validate_expected_string(
845:        obj.get("schema_version"),
846:        "schema_version",
847:        descriptor.schema_version,
848:        &mut result,
849:    );
850:    require_non_empty_string(obj.get("record_id"), "record_id", &mut result);
851:    validate_expected_string(
852:        obj.get("record_kind"),
853:        "record_kind",
854:        descriptor.record_kind,
855:        &mut result,
856:    );
857:    validate_project_profile_kind(obj.get("project_profile_kind"), &mut result);
858:    require_non_empty_string(obj.get("updated_at"), "updated_at", &mut result);
859:    validate_mirror_state(obj.get("mirror_state"), &mut result);
860:    require_string_array(obj.get("authority_refs"), "authority_refs", &mut result);
861:    require_string_array(obj.get("evidence_refs"), "evidence_refs", &mut result);
862:    validate_profile_extension(obj.get("profile_extension"), &mut result);
863:
864:    match family {
865:        StructuredCollaborationRecordFamily::WorkPacketPacket
866:        | StructuredCollaborationRecordFamily::MicroTaskPacket => {
867:            if let Some(summary_path) = obj.get("summary_record_path") {
868:                require_non_empty_string(Some(summary_path), "summary_record_path", &mut result);
869:            }
870:        }
871:        StructuredCollaborationRecordFamily::WorkPacketSummary
872:        | StructuredCollaborationRecordFamily::MicroTaskSummary => {
873:            require_non_empty_string(obj.get("status"), "status", &mut result);
874:            require_non_empty_string(
875:                obj.get("title_or_objective"),
876:                "title_or_objective",
877:                &mut result,
878:            );
879:            require_string_array(obj.get("blockers"), "blockers", &mut result);
880:            require_non_empty_string(obj.get("next_action"), "next_action", &mut result);
881:        }
882:        StructuredCollaborationRecordFamily::TaskBoardEntry => {
883:            require_non_empty_string(obj.get("task_board_id"), "task_board_id", &mut result);
884:            require_non_empty_string(obj.get("work_packet_id"), "work_packet_id", &mut result);
885:            require_non_empty_string(obj.get("lane_id"), "lane_id", &mut result);
886:            require_non_empty_string(obj.get("token"), "token", &mut result);
887:            require_u64_like(obj.get("display_order"), "display_order", &mut result);
888:            if let Some(view_ids) = obj.get("view_ids") {
889:                require_string_array(Some(view_ids), "view_ids", &mut result);
890:            }
891:        }
892:        StructuredCollaborationRecordFamily::TaskBoardIndex => {
893:            require_non_empty_string(obj.get("task_board_id"), "task_board_id", &mut result);
894:            require_string_array(obj.get("view_ids"), "view_ids", &mut result);
895:            require_value_array(obj.get("rows"), "rows", &mut result);
896:        }
897:        StructuredCollaborationRecordFamily::TaskBoardView => {
