928:pub fn validate_structured_collaboration_summary_join(
929:    detail_family: StructuredCollaborationRecordFamily,
930:    detail: &Value,
931:    summary_family: StructuredCollaborationRecordFamily,
932:    summary: &Value,
933:) -> StructuredCollaborationValidationResult {
934:    let mut result = StructuredCollaborationValidationResult::success(detail_family);
935:    result.merge(validate_structured_collaboration_record(
936:        detail_family,
937:        detail,
938:    ));
939:    result.merge(validate_structured_collaboration_record(
940:        summary_family,
941:        summary,
942:    ));
943:
944:    let detail_descriptor = structured_collaboration_schema_descriptor(detail_family);
945:    if detail_descriptor.summary_family != Some(summary_family) {
946:        result.push_issue(
947:            StructuredCollaborationValidationCode::SummaryJoinMismatch,
948:            "summary_family",
949:            detail_descriptor
950:                .summary_family
951:                .map(|family| format!("{family:?}")),
952:            Some(format!("{summary_family:?}")),
953:            "detail and summary families do not form a valid structured collaboration pair",
954:        );
955:        return result;
956:    }
957:
958:    let Some(detail_obj) = detail.as_object() else {
959:        return result;
960:    };
961:    let Some(summary_obj) = summary.as_object() else {
962:        return result;
963:    };
964:
965:    compare_string_field(detail_obj, summary_obj, "record_id", &mut result);
966:    compare_string_field(detail_obj, summary_obj, "record_kind", &mut result);
967:    compare_string_field(detail_obj, summary_obj, "project_profile_kind", &mut result);
968:    compare_string_arrays(detail_obj, summary_obj, "authority_refs", &mut result);
969:    compare_string_arrays(detail_obj, summary_obj, "evidence_refs", &mut result);
970:
971:    result
972:}
