1350:fn validate_profile_extension(
1351:    value: Option<&Value>,
1352:    result: &mut StructuredCollaborationValidationResult,
1353:) {
1354:    let Some(value) = value else {
1355:        return;
1356:    };
1357:    if value.is_null() {
1358:        return;
1359:    }
1360:
1361:    let Some(obj) = value.as_object() else {
1362:        result.push_issue(
1363:            StructuredCollaborationValidationCode::InvalidFieldType,
1364:            "profile_extension",
1365:            Some("object".to_string()),
1366:            Some(json_type_name(value).to_string()),
1367:            "profile_extension must be an object when present",
1368:        );
1369:        return;
1370:    };
1371:
1372:    require_non_empty_string(
1373:        obj.get("extension_schema_id"),
1374:        "profile_extension.extension_schema_id",
1375:        result,
1376:    );
1377:    require_non_empty_string(
1378:        obj.get("extension_schema_version"),
1379:        "profile_extension.extension_schema_version",
1380:        result,
1381:    );
1382:    if obj.get("compatibility").is_none() {
1383:        result.push_issue(
1384:            StructuredCollaborationValidationCode::IncompatibleProfileExtension,
1385:            "profile_extension.compatibility",
1386:            Some("compatibility metadata".to_string()),
1387:            None,
1388:            "profile_extension must declare compatibility metadata",
1389:        );
1390:    } else if profile_extension_is_breaking(obj.get("compatibility")) {
1391:        result.push_issue(
1392:            StructuredCollaborationValidationCode::IncompatibleProfileExtension,
1393:            "profile_extension.compatibility",
1394:            Some("non-breaking compatibility".to_string()),
1395:            compatibility_repr(obj.get("compatibility")),
1396:            "profile_extension declares breaking compatibility and must be rejected deterministically",
1397:        );
1398:    }
1399:}
