1401:fn profile_extension_is_breaking(value: Option<&Value>) -> bool {
1402:    match value {
1403:        Some(Value::String(raw)) => raw.trim().eq_ignore_ascii_case("breaking"),
1404:        Some(Value::Object(obj)) => {
1405:            obj.get("breaking")
1406:                .and_then(Value::as_bool)
1407:                .unwrap_or(false)
1408:                || obj
1409:                    .get("mode")
1410:                    .and_then(Value::as_str)
1411:                    .map(|mode| mode.eq_ignore_ascii_case("breaking"))
1412:                    .unwrap_or(false)
1413:        }
1414:        _ => false,
1415:    }

